const stages=['commit','execute','prove','evaluate','select','canary','rollback'];
const presets={router:'Promote a proof-conditioned routing rule that selects smaller agent constellations when replay evidence shows equal verified value at lower cost and risk.',validator:'Upgrade the Verifier Mesh with a contradiction-coverage rule that blocks publication when primary sources, replay, or private-boundary status are missing.',capability:'Promote a reusable capability package only after replay proves it improves the next mission without increasing risk or proof debt.',workflow:'Upgrade a mission workflow from static report generation to Evidence Docket, verifier report, risk ledger, action graph, and Chronicle handoff.',policy:'Update a governance policy so high-impact actions require canary scope, challenge window, rollback receipt, and human review.'};
const counts={promoted:0,canary:0,rollback:0};
const $=id=>document.getElementById(id);
function vals(){return {proof:+$('proof').value,eval:+$('eval').value,value:+$('value').value,transfer:+$('transfer').value,risk:+$('risk').value,rollback:+$('rollback').value,canary:+$('canary').value,challenge:+$('challenge').value,boundary:+$('boundary').value};}
function sync(){document.querySelectorAll('.uf-sliders label').forEach(l=>{const i=l.querySelector('input'),s=l.querySelector('span'); if(s) s.textContent=i.value;});}
function density(v){return Math.round((v.proof*1.15+v.eval*1.05+v.value+v.transfer*.85+v.risk+v.rollback*1.1+v.canary*.95+v.challenge+v.boundary*1.15)/9.25);}
function gates(v){return [
 ['ProofValid',v.proof>=70],['EvalPass',v.eval>=70],['VerifiedValue',v.value>=60],['TransferReady',v.transfer>=58],['RiskControlled',v.risk>=68],['RollbackReady',v.rollback>=75],['CanaryReady',v.canary>=66],['ChallengeCleared',v.challenge>=72],['ScopeAuthorized',v.boundary>=80]];}
function decision(v){const g=gates(v), pass=g.every(x=>x[1]), D=density(v); if(v.boundary<70) return 'QUARANTINE_PRIVATE_APPENDIX'; if(v.rollback<62) return 'ROLLBACK_REQUIRED'; if(v.proof<60 || v.eval<60) return 'REJECT_UPGRADE_RIGHT'; if(!pass) return 'CANARY_ONLY_NEEDS_MORE_PROOF'; if(D>=78) return 'UPGRADE_RIGHT_GRANTED_AFTER_HUMAN_REVIEW'; return 'SELECTION_CERTIFICATE_HELD_FOR_REVIEW';}
function certificate(mode='gate'){const v=vals(), d=decision(v); return {object:'ProofBackedUpgradeDocket',version:'v25',demo:'Proof-Backed Upgrade Foundry',generatedAt:new Date().toISOString(),publicSafety:{noUserDataWanted:true,noAccount:true,noCookies:true,noAnalytics:true,noStorage:true,noWalletConnection:true,noNetworkRequest:true,noTokenRoute:true,noTransactionBroadcast:true,noProductionAuthority:true},goalOSCommit:{candidateClass:$('artifactPreset').value,proposal:$('proposal').value.slice(0,760),authority:'human-review-required',claimBoundary:'browser-local demonstration only; no factual certification; no external action'},runCommitment:{execution:'local-ui-simulation',allowedTools:['none'],budget:'static browser runtime',dataBoundary:'public-safe text only'},proofPacket:{proofIntegrity:v.proof,evalPassStrength:v.eval,verifiedValue:v.value,transferReadiness:v.transfer,costRiskBoundary:v.risk,publicPrivateBoundary:v.boundary},selectionCertificate:{decision:d,upgradeDensity:density(v),hardGates:Object.fromEntries(gates(v)),scope:'demo-only-no-production-authority',canaryStages:['1% simulation','5% simulation','15% simulation','human review'],challengeWindow:'simulated public review gate',rollbackTarget:v.rollback>=75?'prior-safe-version':'missing-or-weak',requiresHumanReview:true},rolloutReceipt:{canaryHealth:v.canary,monitoring:'simulated',externalActions:0},rollbackReceipt:{rollbackReadiness:v.rollback,rollbackDrill:mode==='rollback'?'executed-local-drill':'available-if-gate-passes'},protocolObjects:['GoalOSCommit','RunCommitment','ProofPacket','EvalAttestation','SelectionCertificate','RolloutReceipt','RollbackReceipt','EvidenceDocket']};}
function renderStages(active=-1){$('ufStagebar').innerHTML=stages.map((s,i)=>`<div class="${i<=active?'active':''}">${s}</div>`).join('');}
function trace(kind,msg,cls=''){const el=document.createElement('div'); el.className='uf-event '+cls; el.textContent=`${kind.toUpperCase()} · ${msg}`; $('ufTrace').prepend(el);}
function renderGates(v){$('gateGrid').innerHTML=gates(v).map(([name,ok])=>`<div class="uf-gate ${ok?'pass':'fail'}"><b>${ok?'PASS':'BLOCK'} · ${name}</b><span>${ok?'Gate satisfied.':'Gate blocks promotion.'}</span></div>`).join('');}
function render(mode='gate'){const obj=certificate(mode), v=vals(); $('densityScore').textContent=obj.selectionCertificate.upgradeDensity; $('gateResult').textContent=obj.selectionCertificate.decision; $('authorityState').textContent=obj.selectionCertificate.decision.includes('GRANTED')?'HUMAN REVIEW':'WITHHELD'; $('certificateJson').textContent=JSON.stringify(obj,null,2); renderGates(v); $('ufPromoted').textContent=counts.promoted; $('ufCanary').textContent=counts.canary; $('ufRollback').textContent=counts.rollback; return obj;}
async function run(mode='gate'){$('ufTrace').innerHTML=''; renderStages(-1); const v=vals(); const rows=[['commit','GoalOSCommit seals the upgrade objective, authority boundary, risk class, and rollback obligations.'],['execute','RunCommitment keeps execution local and bounded: no tools, no wallet, no network, no external action.'],['prove',v.proof>=70?'ProofPacket satisfies integrity threshold.':'ProofPacket is incomplete; upgrade cannot propagate.'],['evaluate',v.eval>=70?'EvalAttestation clears baseline and policy checks.':'EvalAttestation is weak; reviewer must require more evidence.'],['select',decision(v).includes('REJECT')?'SelectionCertificate rejects the upgrade right.':decision(v).includes('CANARY')?'SelectionCertificate permits canary only.':'SelectionCertificate holds authority for human review.'],['canary',v.canary>=66?'Canary simulation is stable within monitoring threshold.':'Canary health weak; wider rollout blocked.'],['rollback',v.rollback>=75?'RollbackReceipt target is ready before release.':'Rollback target missing or weak; release blocked.']]; for(let i=0;i<rows.length;i++){renderStages(i); await new Promise(r=>setTimeout(r,90)); const cls=rows[i][1].includes('incomplete')||rows[i][1].includes('weak')||rows[i][1].includes('blocked')||rows[i][1].includes('missing')?'bad':rows[i][1].includes('canary only')?'warn':''; trace(rows[i][0],rows[i][1],cls);} const obj=render(mode); if(obj.selectionCertificate.decision.includes('GRANTED')) counts.promoted++; if(obj.selectionCertificate.decision.includes('CANARY')||mode==='canary') counts.canary++; if(obj.selectionCertificate.decision.includes('ROLLBACK')||mode==='rollback') counts.rollback++; render(mode);}
function runCanary(){const ids=['proof','eval','value','transfer','risk','rollback','canary','challenge','boundary']; const vv=[76,73,70,62,72,79,67,73,84]; ids.forEach((id,i)=>$(id).value=vv[i]); sync(); run('canary');}
function forceRollback(){const ids=['proof','eval','value','transfer','risk','rollback','canary','challenge','boundary']; const vv=[82,81,77,70,73,42,61,78,87]; ids.forEach((id,i)=>$(id).value=vv[i]); sync(); run('rollback');}
function reset(){Object.entries({proof:86,eval:82,value:79,transfer:73,risk:76,rollback:88,canary:81,challenge:84,boundary:93}).forEach(([k,v])=>$(k).value=v); $('artifactPreset').value='router'; $('proposal').value=presets.router; counts.promoted=0;counts.canary=0;counts.rollback=0; $('ufTrace').innerHTML=''; $('certificateJson').textContent='Run the gate to generate a SelectionCertificate.'; $('densityScore').textContent='—'; $('gateResult').textContent='NOT RUN'; $('authorityState').textContent='NONE'; renderStages(-1); renderGates(vals()); sync(); $('ufPromoted').textContent='0'; $('ufCanary').textContent='0'; $('ufRollback').textContent='0';}
function download(){const obj=certificate('export'); const blob=new Blob([JSON.stringify(obj,null,2)],{type:'application/json'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='goalos-proof-backed-upgrade-certificate-v25.json'; document.body.append(a); a.click(); a.remove(); setTimeout(()=>URL.revokeObjectURL(a.href),800);}
async function copyBrief(){const obj=certificate('brief'); const text=`Proof-Backed Upgrade Foundry: ${obj.selectionCertificate.decision}. Density ${obj.selectionCertificate.upgradeDensity}/100. Authority remains ${obj.selectionCertificate.requiresHumanReview?'human-review gated':'withheld'}. Browser-local public-safe demo only.`; try{await navigator.clipboard.writeText(text); trace('brief','Review brief copied locally.');}catch{trace('brief',text);}}
function field(){const c=$('upgradeField'),ctx=c.getContext('2d');let dots=[];function resize(){c.width=innerWidth*devicePixelRatio;c.height=innerHeight*devicePixelRatio;dots=Array.from({length:150},()=>({x:Math.random()*c.width,y:Math.random()*c.height,v:(.25+Math.random()*.7)*devicePixelRatio,r:(.7+Math.random()*2.2)*devicePixelRatio,a:.25+Math.random()*.65}));}function draw(){ctx.clearRect(0,0,c.width,c.height);for(const d of dots){ctx.beginPath();ctx.fillStyle=`rgba(105,255,218,${d.a})`;ctx.arc(d.x,d.y,d.r,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.strokeStyle=`rgba(116,223,255,${d.a*.23})`;ctx.moveTo(d.x,d.y+d.r*7);ctx.lineTo(d.x,d.y+d.r*24);ctx.stroke();d.y-=d.v;if(d.y<-30){d.y=c.height+30;d.x=Math.random()*c.width;}}requestAnimationFrame(draw);}addEventListener('resize',resize,{passive:true});resize();draw();}
$('artifactPreset').addEventListener('change',e=>{$('proposal').value=presets[e.target.value];});document.querySelectorAll('.uf-sliders input').forEach(i=>i.addEventListener('input',()=>{sync();renderGates(vals());}));$('runGate').addEventListener('click',()=>run('gate'));$('runCanary').addEventListener('click',runCanary);$('forceRollback').addEventListener('click',forceRollback);$('resetUpgrade').addEventListener('click',reset);$('downloadCertificate').addEventListener('click',download);$('copyUpgradeBrief').addEventListener('click',copyBrief);renderStages(-1);renderGates(vals());sync();field();